70: /**
71:  * The current version of the dashboard schema.
72:  *
73:  * NOTE: Schema version 42 is the FINAL version for the v1 dashboard API.
74:  * DO NOT increment this number or add new schema migrations.
75:  *
76:  * This is necessary due to the migration of the legacy dashboards API to the app platform.
77:  *
78:  * For panel-specific migrations, implement them as panel migrations in the
79:  * individual panel plugin migration handlers instead of adding new schema versions.
80:  *
81:  * Legacy migration instructions (for reference only):
82:  * To add a dashboard migration increment this number
83:  * and then add your migration at the bottom of 'updateSchema'
84:  * hint: search "Add migration here"
85:  *
86:  * This number also needs to be updated on the CUE schema:
87:  * kinds/dashboard/dashboard_kind.cue
88:  * Example PR: #87712
89:  */
90: export const DASHBOARD_SCHEMA_VERSION = 42;
91: export class DashboardMigrator {
92:   dashboard: DashboardModel;
93: 
94:   constructor(dashboardModel: DashboardModel) {
95:     this.dashboard = dashboardModel;
96: 
97:     // for tests to pass
98:     if (!getDataSourceSrv()) {
99:       setDataSourceSrv(new DatasourceSrv());
100:     }
101:   }
102: 
103:   updateSchema(old: any, targetSchemaVersion?: number) {
104:     let i, j, k, n;
105:     const oldVersion = this.dashboard.schemaVersion;
106:     const panelUpgrades: PanelSchemeUpgradeHandler[] = [];
107:     const finalTargetVersion = targetSchemaVersion || DASHBOARD_SCHEMA_VERSION;
108: 
109:     if (oldVersion === finalTargetVersion) {
110:       return;
111:     }
112: 
113:     // version 2 schema changes
114:     if (oldVersion < 2 && finalTargetVersion >= 2) {
115:       if (old.services) {
116:         if (old.services.filter) {
117:           this.dashboard.time = old.services.filter.time;
118:           this.dashboard.templating.list = old.services.filter.list || [];
119:         }
120:       }
121: 
122:       // we used to have graphite panel type migration logic here
123:       // but this is handled by auto migration, see public/app/features/dashboard/state/getPanelPluginToMigrateTo.ts
124:     }
125: 
126:     // schema version 3 changes
127:     if (oldVersion < 3 && finalTargetVersion >= 3) {
128:       // Panel ID assignment is now handled by ensurePanelsHaveUniqueIds() in DashboardModel
129:       // and the grid layout migration properly handles panels without IDs in rows
130:     }
131: 
132:     // schema version 4 changes
