788: 	removeIfDefaultValue(variable, "datasource", nil)
789: 
790: 	// Remove properties that frontend omits in getSaveModel
791: 	delete(variable, "index")
792: 
793: 	// Apply variable type-specific logic
794: 	if variableType, ok := variable["type"].(string); ok {
795: 		switch variableType {
796: 		case "query":
797: 			// Query variables: keep options: [] if refresh !== never (matches frontend getSaveModel logic)
798: 			refresh := schemaversion.GetIntValue(variable, "refresh", 1) // Default to 1 (onDashboardLoad) if not specified
799: 			if refresh != 0 {                                            // 0 = VariableRefreshNever
800: 				if _, hasOptions := variable["options"]; !hasOptions {
801: 					variable["options"] = []interface{}{}
802: 				}
803: 			}
804: 		case "constant":
805: 			// Constant variables: remove options completely
806: 			delete(variable, "options")
807: 		case "datasource":
808: 			// Datasource variables: always set options to empty array
809: 			variable["options"] = []interface{}{}
810: 		case "custom":
811: 			// Custom variables: no special handling (just return rest)
812: 			// This is the default behavior - no additional processing needed
813: 		case "textbox":
814: 			// Textbox variables: handle query vs originalQuery logic
815: 			// For now, just return rest (no special handling needed for basic cases)
816: 		case "adhoc":
817: 			// Adhoc variables: no special handling
818: 			// This is the default behavior - no additional processing needed
819: 		}
820: 	}
821: }
