18: // V16 migrates dashboard layout from the old row-based system to the modern grid-based layout.
19: // This migration follows the exact logic from DashboardMigrator.ts to ensure consistency between frontend and backend.
20: func V16(_ context.Context, dashboard map[string]interface{}) error {
21: 	dashboard["schemaVersion"] = 16
22: 
23: 	upgradeToGridLayout(dashboard)
24: 
25: 	return nil
26: }
