28: func upgradeToGridLayout(dashboard map[string]interface{}) {
29: 	rowsInterface, ok := dashboard["rows"]
30: 	if !ok {
31: 		return
32: 	}
33: 
34: 	rows, ok := rowsInterface.([]interface{})
35: 	if !ok {
36: 		return
37: 	}
38: 
39: 	// Handle empty rows
40: 	if len(rows) == 0 {
41: 		delete(dashboard, "rows")
42: 		return
43: 	}
44: 
45: 	yPos := 0
46: 	widthFactor := gridColumnCount / 12.0
47: 
48: 	// Find max panel ID (lines 1014-1021 in TS)
49: 	maxPanelID := getMaxPanelID(rows)
50: 	nextRowID := maxPanelID + 1
51: 
52: 	// Match frontend: dashboard.panels already exists with top-level panels
53: 	// The frontend's this.dashboard.panels is initialized in the constructor with existing panels
54: 	// Then upgradeToGridLayout adds more panels to it
55: 
56: 	// Initialize panels array - make a copy to avoid modifying the original
57: 	panels := []interface{}{}
58: 	if existingPanels, ok := dashboard["panels"].([]interface{}); ok && len(existingPanels) > 0 {
59: 		// Copy existing panels to preserve order
60: 		panels = append(panels, existingPanels...)
61: 	}
62: 
63: 	// Add special "row" panels if even one row is collapsed, repeated or has visible title (line 1028 in TS)
64: 	showRows := shouldShowRows(rows)
65: 
66: 	// Process each row (line 1030 in TS)
67: 	for _, rowInterface := range rows {
68: 		row, ok := rowInterface.(map[string]interface{})
69: 		if !ok {
70: 			continue
71: 		}
72: 
73: 		// Skip repeated rows (line 1031-1033 in TS)
74: 		if repeatIteration, hasRepeatIteration := row["repeatIteration"]; hasRepeatIteration && repeatIteration != nil {
75: 			continue
76: 		}
77: 
78: 		height := getRowHeight(row)
79: 		rowGridHeight := getGridHeight(height)
80: 		// Check if collapse property exists and get its value
81: 		collapseValue, hasCollapseProperty := row["collapse"]
82: 		isCollapsed := false
83: 		if hasCollapseProperty {
84: 			if b, ok := collapseValue.(bool); ok {
85: 				isCollapsed = b
86: 			}
87: 		}
88: 
89: 		var rowPanel map[string]interface{}
90: 
91: 		// First pass: assign IDs to panels that don't have them
92: 		panelsInRow, ok := row["panels"].([]interface{})
93: 		if !ok {
94: 			panelsInRow = []interface{}{}
95: 		}
96: 
97: 		for _, panelInterface := range panelsInRow {
98: 			panel, ok := panelInterface.(map[string]interface{})
99: 			if !ok {
100: 				continue
101: 			}
102: 			// Assign ID if missing
103: 			if _, hasID := panel["id"]; !hasID {
104: 				panel["id"] = nextRowID
105: 				nextRowID++
106: 			}
107: 		}
108: 
109: 		if showRows {
110: 			// add special row panel (lines 1041-1058 in TS)
111: 			rowPanel = map[string]interface{}{
112: 				"id":     nextRowID,
113: 				"type":   "row",
114: 				"title":  GetStringValue(row, "title"),
115: 				"repeat": GetStringValue(row, "repeat"),
116: 				"panels": []interface{}{},
117: 				"gridPos": map[string]interface{}{
118: 					"x": 0,
119: 					"y": yPos,
120: 					"w": int(gridColumnCount),
121: 					"h": rowGridHeight,
122: 				},
123: 			}
124: 
125: 			// Match frontend behavior: rowPanel.collapsed = row.collapse (line 1065 in TS)
126: 			// Only set collapsed property if the original row had a collapse property
127: 			if hasCollapseProperty {
128: 				rowPanel["collapsed"] = isCollapsed
129: 			}
130: 			nextRowID++
131: 			yPos++
132: 		}
133: 
134: 		rowArea := newRowArea(rowGridHeight, gridColumnCount, yPos)
135: 
136: 		// Process all panels in this row (lines 1062-1087 in TS)
137: 		for _, panelInterface := range panelsInRow {
138: 			panel, ok := panelInterface.(map[string]interface{})
139: 			if !ok {
140: 				continue
141: 			}
142: 
143: 			// Match frontend logic: panel.span = panel.span || DEFAULT_PANEL_SPAN (line 1082 in TS)
144: 			span := GetFloatValue(panel, "span", 0)
145: 			if span == 0 {
146: 				span = defaultPanelSpan
147: 			}
148: 
149: 			panelWidth, panelHeight := calculatePanelDimensionsFromSpan(span, panel, widthFactor, rowGridHeight)
150: 
151: 			panelPos := rowArea.getPanelPosition(panelHeight, panelWidth)
152: 			yPos = rowArea.yPos
153: 
154: 			// Set gridPos (lines 1072-1077 in TS)
155: 			panel["gridPos"] = map[string]interface{}{
156: 				"x": GetIntValue(panelPos, "x", 0),
157: 				"y": yPos + GetIntValue(panelPos, "y", 0),
158: 				"w": panelWidth,
159: 				"h": panelHeight,
160: 			}
161: 			rowArea.addPanel(panel["gridPos"].(map[string]interface{}))
162: 
163: 			// Remove span (line 1080 in TS)
164: 			delete(panel, "span")
165: 
166: 			// Match frontend logic: lines 1101-1105 in TS
167: 			if rowPanel != nil && isCollapsed {
168: 				// Add to collapsed row's nested panels (line 1102)
169: 				if rowPanelPanels, ok := rowPanel["panels"].([]interface{}); ok {
170: 					rowPanel["panels"] = append(rowPanelPanels, panel)
171: 				}
172: 			} else {
173: 				// Add directly to panels array like frontend (line 1104)
174: 				panels = append(panels, panel)
175: 			}
176: 		}
177: 
178: 		// Add row panel after regular panels from this row (lines 1108-1110 in TS)
179: 		if rowPanel != nil {
180: 			panels = append(panels, rowPanel)
181: 		}
182: 
183: 		// Update yPos (lines 1093-1095 in TS)
184: 		if rowPanel == nil || !isCollapsed {
185: 			yPos += rowGridHeight
186: 		}
187: 	}
188: 
189: 	// Update the dashboard
190: 	dashboard["panels"] = panels
191: 	delete(dashboard, "rows")
192: }
