194: // rowArea represents dashboard row filled by panels
195: type rowArea struct {
196: 	area   []int
197: 	yPos   int
198: 	height int
199: }
200: 
201: func newRowArea(height int, width int, rowYPos int) *rowArea {
202: 	area := make([]int, width)
203: 	return &rowArea{
204: 		area:   area,
205: 		yPos:   rowYPos,
206: 		height: height,
207: 	}
208: }
209: 
210: func (r *rowArea) reset() {
211: 	for i := range r.area {
212: 		r.area[i] = 0
213: 	}
214: }
215: 
216: func (r *rowArea) addPanel(gridPos map[string]interface{}) {
217: 	x := GetIntValue(gridPos, "x", 0)
218: 	y := GetIntValue(gridPos, "y", 0)
219: 	w := GetIntValue(gridPos, "w", 0)
220: 	h := GetIntValue(gridPos, "h", 0)
221: 
222: 	for i := x; i < x+w && i < len(r.area); i++ {
223: 		newHeight := y + h - r.yPos
224: 		if newHeight > r.area[i] {
225: 			r.area[i] = newHeight
226: 		}
227: 	}
228: }
229: 
230: func (r *rowArea) getPanelPosition(panelHeight int, panelWidth int) map[string]interface{} {
231: 	var startPlace, endPlace int
232: 	found := false
233: 
234: 	// Find available space from right to left
235: 	for i := len(r.area) - 1; i >= 0; i-- {
236: 		if r.height-r.area[i] > 0 {
237: 			if !found {
238: 				endPlace = i
239: 				found = true
240: 			} else {
241: 				if i < len(r.area)-1 && r.area[i] <= r.area[i+1] {
242: 					startPlace = i
243: 				} else {
244: 					break
245: 				}
246: 			}
247: 		} else {
248: 			break
249: 		}
250: 	}
251: 
252: 	if found && endPlace-startPlace >= panelWidth-1 {
253: 		// Find max height in the range
254: 		yPos := 0
255: 		for i := startPlace; i <= endPlace && i < len(r.area); i++ {
256: 			if r.area[i] > yPos {
257: 				yPos = r.area[i]
258: 			}
259: 		}
260: 		return map[string]interface{}{
261: 			"x": startPlace,
262: 			"y": yPos,
263: 		}
264: 	}
265: 
266: 	// Wrap to next row
267: 	r.yPos += r.height
268: 	r.reset()
269: 	return r.getPanelPosition(panelHeight, panelWidth)
270: }
