272: func getMaxPanelID(rows []interface{}) int {
273: 	maxID := 0
274: 	hasValidID := false
275: 
276: 	for _, rowInterface := range rows {
277: 		if row, ok := rowInterface.(map[string]interface{}); ok {
278: 			if panels, ok := row["panels"].([]interface{}); ok {
279: 				for _, panelInterface := range panels {
280: 					if panel, ok := panelInterface.(map[string]interface{}); ok {
281: 						if id := GetIntValue(panel, "id", 0); id > 0 {
282: 							hasValidID = true
283: 							if id > maxID {
284: 								maxID = id
285: 							}
286: 						}
287: 					}
288: 				}
289: 			}
290: 		}
291: 	}
292: 
293: 	// If no valid IDs found, return 0 (matches frontend behavior)
294: 	if !hasValidID {
295: 		return 0
296: 	}
297: 
298: 	return maxID
299: }
