301: func shouldShowRows(rows []interface{}) bool {
302: 	for _, rowInterface := range rows {
303: 		if row, ok := rowInterface.(map[string]interface{}); ok {
304: 			collapse := GetBoolValue(row, "collapse")
305: 			showTitle := GetBoolValue(row, "showTitle")
306: 			repeat := GetStringValue(row, "repeat")
307: 
308: 			if collapse || showTitle || repeat != "" {
309: 				return true
310: 			}
311: 		}
312: 	}
313: 	return false
314: }
