316: func getRowHeight(row map[string]interface{}) float64 {
317: 	if height, ok := row["height"]; ok {
318: 		if h, ok := ConvertToFloat(height); ok {
319: 			return h
320: 		}
321: 	}
322: 	return defaultRowHeight
323: }
