332: func calculatePanelDimensionsFromSpan(span float64, panel map[string]interface{}, widthFactor float64, defaultHeight int) (int, int) {
333: 	// span should already be normalized by caller (line 1082 in DashboardMigrator.ts)
334: 
335: 	if minSpan, hasMinSpan := panel["minSpan"]; hasMinSpan {
336: 		if minSpanFloat, ok := ConvertToFloat(minSpan); ok && minSpanFloat > 0 {
337: 			panel["minSpan"] = int(math.Min(float64(gridColumnCount), (float64(gridColumnCount)/12.0)*minSpanFloat))
338: 		}
339: 	}
340: 
341: 	// Match frontend logic: Math.floor(panel.span) * widthFactor (line 914 in DashboardMigrator.ts)
342: 	// Frontend floors the span FIRST, then multiplies by widthFactor
343: 	panelWidth := int(math.Floor(span)) * int(widthFactor)
344: 	panelHeight := defaultHeight
345: 
346: 	if panelHeightValue, hasHeight := panel["height"]; hasHeight {
347: 		if h, ok := ConvertToFloat(panelHeightValue); ok {
348: 			panelHeight = getGridHeight(h)
349: 		}
350: 	}
351: 
352: 	return panelWidth, panelHeight
353: }
